@using Microsoft.JSInterop
@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="@DropZoneClass">
    <p class="drop-zone-text">Drag &amp; drop files here</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _entries)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="error-message">@entry.Error</span>
                }
                else
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@(string.IsNullOrEmpty(entry.Info.Type) ? "unknown" : entry.Info.Type)</span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;

    private readonly List<FileEntry> _entries = new();

    private string DropZoneClass => _isDragOver ? "drop-zone drop-zone-highlight" : "drop-zone";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-91c9e5fa14f9476bacb30fb40bf0852a/Components/FileDropZone/FileDropZone.razor.js");
            await _module.InvokeVoidAsync("init", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() { _isDragOver = true; StateHasChanged(); }

    [JSInvokable]
    public void OnDragLeave() { _isDragOver = false; StateHasChanged(); }

    [JSInvokable]
    public async Task OnDrop(FileInfo[] files)
    {
        _isDragOver = false;

        foreach (var file in files)
        {
            string? error = file.Size > MaxFileSize
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;

            _entries.Add(new FileEntry(file, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();

        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private record FileEntry(FileInfo Info, string? Error);
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    min-height: 160px;
    background-color: #f8f9fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: default;
}

.drop-zone-highlight {
    background-color: #d4edda;
    border-color: #28a745;
}

.drop-zone-text {
    color: #6c757d;
    margin: 0;
    font-size: 1.1rem;
    pointer-events: none;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-name {
    font-weight: 600;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    max-width: 250px;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.9rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.9rem;
    flex: 1;
}

.btn-remove {
    margin-left: auto;
    border: none;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.9rem;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
}

.btn-remove:hover {
    background: #dc3545;
    color: #fff;
}

let dropZone, dotNetRef, controller;

export function init(element, ref) {
    dropZone = element;
    dotNetRef = ref;
    controller = new AbortController();
    const opts = { signal: controller.signal };

    dropZone.addEventListener('dragenter', handleDragEnter, opts);
    dropZone.addEventListener('dragover', handleDragOver, opts);
    dropZone.addEventListener('dragleave', handleDragLeave, opts);
    dropZone.addEventListener('drop', handleDrop, opts);
}

export function dispose() {
    controller?.abort();
}

function handleDragEnter(e) {
    e.preventDefault();
    dotNetRef.invokeMethodAsync('OnDragEnter');
}

function handleDragOver(e) {
    e.preventDefault();
}

function handleDragLeave(e) {
    // Only fire when actually leaving the drop zone, not entering a child
    if (!dropZone.contains(e.relatedTarget)) {
        dotNetRef.invokeMethodAsync('OnDragLeave');
    }
}

function handleDrop(e) {
    e.preventDefault();
    const files = Array.from(e.dataTransfer.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type
    }));
    dotNetRef.invokeMethodAsync('OnDrop', files);
}

