@using Microsoft.JSInterop
@using sv_91c9e5fa14f9476bacb30fb40bf0852a.Components.FileDropZone
@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="@DropZoneClass">
    <p class="drop-zone-text">Drag &amp; drop files here</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _entries)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="error-message">@entry.Error</span>
                }
                else
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@(string.IsNullOrEmpty(entry.Info.Type) ? "unknown" : entry.Info.Type)</span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;

    private readonly List<FileEntry> _entries = new();

    private string DropZoneClass => _isDragOver ? "drop-zone drop-zone-highlight" : "drop-zone";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-91c9e5fa14f9476bacb30fb40bf0852a/Components/FileDropZone/FileDropZone.razor.js");
            await _module.InvokeVoidAsync("init", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() { _isDragOver = true; StateHasChanged(); }

    [JSInvokable]
    public void OnDragLeave() { _isDragOver = false; StateHasChanged(); }

    [JSInvokable]
    public async Task OnDrop(FileInfo[] files)
    {
        _isDragOver = false;

        foreach (var file in files)
        {
            string? error = file.Size > MaxFileSize
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;

            _entries.Add(new FileEntry(file, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();

        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private record FileEntry(FileInfo Info, string? Error);
}

